// // This module is designed to decrement a 4-bit binary counter on each positive edge of the clock signal and reset it to zero when the reset signal is high.
module up_counter(CLK, RST, Q);
input CLK, RST;
output reg [3:0] Q;

always @(posedge CLK or posedge RST) begin
    if (RST) 
        Q <= 4'b0000;
    else
        Q <= Q + 1;
end

endmodule
